-- ============================================================================
-- Annuaire MSP — seed d'import des carnets d'adresses
-- Généré automatiquement. À exécuter APRÈS schema.sql, dans Supabase → SQL Editor.
-- Ré-exécutable sans doublon (id déterministes + on conflict do nothing).
--
-- Sources : carnets individuels d'Anne, Charlène, Aurélien, Antonin
--           + ancien répertoire partagé (Répertoire partagé MSPM V2.xlsx).
-- ============================================================================

-- ---------------------------------------------------------------------------
-- Correspondance carnet -> compte Supabase, PAR EMAIL (aucun UUID codé en dur).
-- Les comptes doivent exister (Auth → Users) : le trigger on_auth_user_created
-- a créé leur fiche dans public.members. Le garde-fou ci-dessous refuse de tourner
-- si l'un d'eux manque, plutôt que d'importer un carnet dans le vide.
-- ---------------------------------------------------------------------------
create temp table seed_owner_map (slug text primary key, email text not null);
-- Les commentaires de l'ancien répertoire partagé ne figurent pas ici : ils sont
-- importés avec author_id = null et s'affichent « Extrait de l'ancien répertoire ».

-- Garde-fou : refuser de tourner si un carnet ne correspond à aucun compte,
-- sinon 300 fiches atterriraient silencieusement dans la liste de personne.
do $$
declare manquants text;
begin
  select string_agg(o.slug || ' -> ' || o.email, ', ') into manquants
  from seed_owner_map o
  where not exists (select 1 from public.members m where m.email = o.email);
  if manquants is not null then
    raise exception 'Comptes introuvables dans public.members : %. Crée-les (Auth -> Users) ou corrige seed_owner_map.', manquants;
  end if;
end $$;

-- ---------------------------------------------------------------------------
-- 1. CONTACTS (1232 fiches)
-- created_by = 1er carnet d'origine ; null pour les fiches issues du seul
-- répertoire partagé (elles n'appartiennent à personne).
-- ---------------------------------------------------------------------------
create temp table seed_contacts (id uuid primary key, creator_slug text);

on conflict (id) do nothing;

on conflict (id) do nothing;

update public.contacts c set created_by = m.id
from seed_contacts s
  join seed_owner_map o on o.slug = s.creator_slug
  join public.members m on m.email = o.email
where c.id = s.id and c.created_by is null;

-- ---------------------------------------------------------------------------
-- 2. COMMENTAIRES (1280) — signés par l'auteur du carnet d'origine.
-- Une fiche connue de 2 médecins porte les avis des 2, chacun attribué.
-- author_id null = « Extrait de l'ancien répertoire » (xlsx, auteur inconnu).
-- ---------------------------------------------------------------------------
create temp table seed_comments (contact_id uuid, slug text, origine text,
                                  type text, texte text);

select s.contact_id, m.id, s.origine, s.type, s.texte
from seed_comments s
  left join seed_owner_map o on o.slug = s.slug
  left join public.members m on m.email = o.email
where not exists (
  select 1 from public.comments x
  where x.contact_id = s.contact_id and x.texte = s.texte
    and x.author_id is not distinct from m.id
);

-- ---------------------------------------------------------------------------
-- 3. « MES CONTACTS » (1236 entrées)
-- Chaque fiche retourne dans la liste perso du/des médecin(s) dont elle vient.
-- Une fiche connue de plusieurs médecins apparaît dans la liste de chacun.
-- Les fiches du seul répertoire partagé n'entrent dans la liste de personne.
-- ---------------------------------------------------------------------------
create temp table seed_list (contact_id uuid, slug text);

select m.id, s.contact_id
from seed_list s
  join seed_owner_map o on o.slug = s.slug
  join public.members m on m.email = o.email
on conflict (member_id, contact_id) do nothing;

-- ---------------------------------------------------------------------------
-- 4. CONTRÔLE — à lire après exécution
-- ---------------------------------------------------------------------------
select 'contacts'     as table, count(*) from public.contacts
union all select 'comments',    count(*) from public.comments
union all select 'list_entries', count(*) from public.list_entries
union all select 'à vérifier',  count(*) from public.contacts where statut = 'a_verifier'
union all select 'fiches vérifiées sur le web', count(*) from public.contacts
           where source_checked_at is not null
union all select 'commentaires signés', count(*) from public.comments where author_id is not null
union all select 'comm. ancien répertoire', count(*) from public.comments
           where origine = 'repertoire_partage'
union all select 'comm. trouvés sur le web', count(*) from public.comments
           where origine = 'enrichissement_web'
union all select 'comm. signalés par la MSP', count(*) from public.comments
           where origine = 'signalement_msp';

-- Carnets dont l'email n'a pas été retrouvé dans members (=> import partiel) :
select o.slug, o.email
from seed_owner_map o
where not exists (select 1 from public.members m where m.email = o.email);
