  ('605c38d4-064a-5e66-99df-9bb0306059b3'::uuid, null, 'enrichissement_web', 'info', 'Secteur 2 adhérent OPTAM : dépassements d''honoraires maîtrisés (source : Annuaire santé Ameli, CNAM, fichier du 2026-07-13).'),
