  ('b495484c-5349-5be6-af45-4a64fca6e23c'::uuid, null, 'enrichissement_web', 'info', 'Autre lieu d''exercice trouvé sur le web : 184 rue du Faubourg Saint-Antoine 75012 (01 49 28 26 63).'),
