  ('0b04da4c-d838-5850-a27d-c97faa44c1b5'::uuid, null, 'enrichissement_web', 'info', 'Le « GOSB » du carnet correspond au Centre de santé de Belleville (CDS de Belleville), 27 rue Levert 75020, où le praticien est bien listé comme ophtalmologue. Cabinet au 2e étage avec ascenseur, entrée accessible (le champ « accès handicapé » de la source reste toutefois « non renseigné » : pmr laissé à false).'),
  ('0b04da4c-d838-5850-a27d-c97faa44c1b5'::uuid, null, 'enrichissement_web', 'info', 'Autre lieu d''exercice trouvé sur le web : CDS de la polyclinique d''Aubervilliers, 55 rue Henri Barbusse 93300 Aubervilliers.'),
