  ('4ebc071c-afa2-5304-83b3-37658fe5963d'::uuid, 'anne', null, 'spec', 'Consulte à domicile pour les bébés sur tout Paris.'),
  ('4ebc071c-afa2-5304-83b3-37658fe5963d'::uuid, 'anne', null, 'info', 'Cabinet rue de Rivoli, avec un gynéco et un gastro. Consulte aussi à la Maison des femmes de Bichat.'),
  ('4ebc071c-afa2-5304-83b3-37658fe5963d'::uuid, null, 'enrichissement_web', 'spec', 'Spécialiste en périnatalité (femmes enceintes, post-accouchement, nourrissons), drainage lymphatique manuel, et prise en charge ostéopathique des femmes ayant subi des violences.'),
  ('4ebc071c-afa2-5304-83b3-37658fe5963d'::uuid, null, 'enrichissement_web', 'info', 'Son profil professionnel confirme les lieux d''exercice notés par le carnet : Cabinet Médical Rivoli à Paris et Maison des Femmes - AP-HP Hôpital Bichat. Elle consulte aussi au Cabinet Clinique Saint-Germain, 12 rue de la Baronne Gérard, 78100 Saint-Germain-en-Laye (téléphone affiché sur ce profil : 01 84 17 27 87 — à rattacher au site de Saint-Germain, non au cabinet parisien).'),
  ('9b76daee-0988-57c2-82ae-e8630a88778b'::uuid, null, 'enrichissement_web', 'spec', 'Orientations affichées : ostéopathie de la femme enceinte, ostéopathie pédiatrique, ostéopathie myofasciale et structurelle — cohérent avec l''orientation « femmes et bébés » du carnet.'),
  ('bf8a882e-cc82-538b-a6a9-6fbdc19f0293'::uuid, 'anne', null, 'reco', 'Reco par Nathalie Dupont.'),
  ('bf8a882e-cc82-538b-a6a9-6fbdc19f0293'::uuid, null, 'enrichissement_web', 'spec', 'Orientations affichées : ostéopathie de la femme enceinte et ostéopathie pédiatrique (cohérent avec « femmes et bébés » du carnet), plus dysfonctionnement temporo-mandibulaire, ostéopathie du sport, crânienne, myofasciale, structurelle et bilan postural.'),
  ('3b826574-da6c-56a4-aee9-6f012f1116a4'::uuid, null, 'enrichissement_web', 'info', 'Deux adresses concurrentes dans le 17e selon les sources : 17 rue Eugène Flachat (cabinet médical Dr Mouy, annuaire des anciens de l''ESO) et 7 avenue Paul Adam (installation plus récente évoquée par d''autres résultats). À trancher avant d''inscrire une adresse.'),
  ('1eb9b1ad-2da4-5b1b-b972-efd77a0d0d18'::uuid, 'anne', null, 'reco', 'Reco par une patiente.'),
